/**
 * Type definitions for the report generation subsystem.
 */

export interface ReportStats {
  totalSessions: number
  totalMessages: number
  totalToolEvents: number
  activeDays: number
  dateRange: { from: string; to: string }
  clientCounts: Record<string, number>
  /** 'YYYY-MM-DD' → session count */
  dayBuckets: Record<string, number>
  /** 'YYYY-WNN' → message count */
  weekBuckets: Record<string, number>
  /** tool name → invocation count */
  toolCounts: Record<string, number>
}

export interface SummaryCache {
  sha256: string
  summary: string
  generated_at: string
}

export interface LinkGraph {
  /** session_id → list of session_ids that reference it */
  backlinks: Record<string, string[]>
  /** session_id → list of session_ids it references */
  forwardLinks: Record<string, string[]>
}

export interface SearchIndexEntry {
  url: string
  title: string
  client: string
  date: string
  snippet: string
}

export interface BuildReportOptions {
  root: string
  output: string
  noAi?: boolean
  pdf?: boolean
  model?: string
}

/**
 * Type definitions for the report generation subsystem.
 */

export interface ReportStats {
  totalSessions: number
  totalMessages: number
  totalToolEvents: number
  activeDays: number
  dateRange: { from: string; to: string }
  clientCounts: Record<string, number>
  /** 'YYYY-MM-DD' → session count */
  dayBuckets: Record<string, number>
  /** 'YYYY-WNN' → message count */
  weekBuckets: Record<string, number>
  /** tool name → invocation count */
  toolCounts: Record<string, number>
}

export interface SummaryCache {
  sha256: string
  summary: string
  generated_at: string
}

export interface LinkGraph {
  /** session_id → list of session_ids that reference it */
  backlinks: Record<string, string[]>
  /** session_id → list of session_ids it references */
  forwardLinks: Record<string, string[]>
}

export interface SearchIndexEntry {
  url: string
  title: string
  client: string
  date: string
  snippet: string
}

export interface BuildReportOptions {
  root: string
  output: string
  noAi?: boolean
  pdf?: boolean
  model?: string
}

/**
 * GitHub Dark-inspired CSS for the report website.
 * Self-contained — no external CDN dependencies.
 */

export const REPORT_CSS = `
:root {
  --bg: #0d1117;
  --bg-secondary: #161b22;
  --bg-card: #21262d;
  --border: #30363d;
  --text: #e6edf3;
  --text-muted: #8b949e;
  --accent: #58a6ff;
  --accent-hover: #79b8ff;
  --green-0: #161b22;
  --green-1: #0e4429;
  --green-2: #006d32;
  --green-3: #26a641;
  --green-4: #39d353;
  --user-bg: #1c2d3e;
  --user-border: #388bfd44;
  --assistant-bg: #1c1c1c;
  --assistant-border: #30363d;
  --code-bg: #161b22;
  --badge-codex: #1f6feb;
  --badge-claude: #6e40c9;
  --badge-gemini: #1a7f37;
  --danger: #f85149;
  --warning: #d29922;
  --success: #3fb950;
  --font-mono: 'SF Mono', 'Consolas', 'Liberation Mono', 'Menlo', monospace;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html { font-size: 16px; scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Helvetica Neue', sans-serif;
  line-height: 1.6;
  min-height: 100vh;
}

a { color: var(--accent); text-decoration: none; }
a:hover { color: var(--accent-hover); text-decoration: underline; }

code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--code-bg);
  padding: 0.15em 0.4em;
  border-radius: 4px;
  border: 1px solid var(--border);
}

pre {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1rem;
  overflow-x: auto;
  margin: 0.75rem 0;
}

pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.875rem;
}

h1, h2, h3, h4, h5, h6 {
  color: var(--text);
  line-height: 1.3;
  margin-bottom: 0.5rem;
}

h1 { font-size: 1.75rem; }
h2 { font-size: 1.375rem; border-bottom: 1px solid var(--border); padding-bottom: 0.4rem; margin-top: 1.5rem; margin-bottom: 0.75rem; }
h3 { font-size: 1.125rem; }

p { margin-bottom: 0.75rem; }

ul, ol { padding-left: 1.5rem; margin-bottom: 0.75rem; }
li { margin-bottom: 0.25rem; }

table { width: 100%; border-collapse: collapse; font-size: 0.9rem; }
th, td { padding: 0.5rem 0.75rem; text-align: left; border-bottom: 1px solid var(--border); }
th { color: var(--text-muted); font-weight: 600; font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.05em; background: var(--bg-secondary); }
tr:hover td { background: var(--bg-secondary); }

/* ── Nav ── */
.nav {
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  padding: 0 1.5rem;
  display: flex;
  align-items: center;
  gap: 0;
  position: sticky;
  top: 0;
  z-index: 100;
}

.nav-brand {
  font-weight: 700;
  font-size: 1rem;
  color: var(--text);
  padding: 0.75rem 1rem 0.75rem 0;
  margin-right: 0.5rem;
  border-right: 1px solid var(--border);
}

.nav-link {
  display: inline-block;
  padding: 0.75rem 1rem;
  color: var(--text-muted);
  font-size: 0.9rem;
  transition: color 0.15s;
}

.nav-link:hover { color: var(--text); text-decoration: none; }
.nav-link.active { color: var(--text); border-bottom: 2px solid var(--accent); }

/* ── Layout ── */
.container { max-width: 1200px; margin: 0 auto; padding: 1.5rem; }

.page-header { margin-bottom: 2rem; }
.page-header h1 { font-size: 1.5rem; }
.page-header .subtitle { color: var(--text-muted); font-size: 0.9rem; margin-top: 0.25rem; }

/* ── Cards ── */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 1.25rem;
  margin-bottom: 1rem;
}

.card-title {
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-muted);
  margin-bottom: 0.5rem;
}

.stat-value {
  font-size: 2rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1;
}

.stat-label { font-size: 0.85rem; color: var(--text-muted); margin-top: 0.25rem; }

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 1rem;
  margin-bottom: 1.5rem;
}

/* ── Charts ── */
.chart-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

@media (max-width: 900px) {
  .chart-grid { grid-template-columns: 1fr; }
}

.chart-card {
  background: var(--bg-card);
