// ---------------------------------------------------------------------------
// Weekly messages line chart (last 52 weeks)
// ---------------------------------------------------------------------------

export function renderWeeklyLine(weekBuckets: Record<string, number>): string {
  const W = 580
  const H = 140
  const padL = 38
  const padR = 12
  const padT = 12
  const padB = 24
  const plotW = W - padL - padR
  const plotH = H - padT - padB

  // Build last 52 weeks array
  const weeks = getLast52Weeks()
  const data = weeks.map(w => weekBuckets[w] ?? 0)
  const maxVal = Math.max(...data, 1)

  const points = data.map((v, i) => {
    const x = padL + (i / (data.length - 1)) * plotW
    const y = padT + plotH - (v / maxVal) * plotH
    return { x, y }
  })

  // Build filled area path
  const linePoints = points.map(p => `${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ')
  const firstX = points[0]?.x ?? padL
  const lastX = points[points.length - 1]?.x ?? (padL + plotW)
  const baseY = padT + plotH

  const areaPath =
    `M${firstX.toFixed(1)},${baseY} ` +
    points.map(p => `L${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(' ') +
    ` L${lastX.toFixed(1)},${baseY} Z`

  // Y axis labels
  const yLabels = [0, Math.round(maxVal / 2), maxVal]
    .map(v => {
      const y = padT + plotH - (v / maxVal) * plotH
      return `<text x="${padL - 4}" y="${y + 4}" font-size="9" fill="#8b949e" text-anchor="end">${v}</text>`
    })
    .join('')

  // X axis: show first and last week labels
  const firstWeek = weeks[0] ?? ''
  const lastWeek = weeks[weeks.length - 1] ?? ''
  const xLabels =
    `<text x="${padL}" y="${H - 4}" font-size="9" fill="#8b949e" text-anchor="start">${escHtml(firstWeek)}</text>` +
    `<text x="${W - padR}" y="${H - 4}" font-size="9" fill="#8b949e" text-anchor="end">${escHtml(lastWeek)}</text>`

  return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" aria-label="Weekly messages">
  <defs>
    <linearGradient id="lineGrad" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#58a6ff" stop-opacity="0.3"/>
      <stop offset="100%" stop-color="#58a6ff" stop-opacity="0.02"/>
    </linearGradient>
  </defs>
  <line x1="${padL}" y1="${padT}" x2="${padL}" y2="${padT + plotH}" stroke="#30363d" stroke-width="1"/>
  <line x1="${padL}" y1="${padT + plotH}" x2="${padL + plotW}" y2="${padT + plotH}" stroke="#30363d" stroke-width="1"/>
  ${yLabels}
  ${xLabels}
  <path d="${areaPath}" fill="url(#lineGrad)"/>
  <polyline points="${linePoints}" fill="none" stroke="#58a6ff" stroke-width="1.5" stroke-linejoin="round" stroke-linecap="round"/>
</svg>`
}

function getLast52Weeks(): string[] {
  const weeks: string[] = []
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  for (let i = 51; i >= 0; i--) {
    const d = new Date(today)
    d.setDate(d.getDate() - i * 7)
    weeks.push(toIsoWeek(d))
  }
  return weeks
}

function toIsoWeek(d: Date): string {
  const thursday = new Date(d)
  thursday.setDate(d.getDate() + (4 - ((d.getDay() + 6) % 7 + 1)))
  const year = thursday.getFullYear()
  const jan4 = new Date(year, 0, 4)
  const week = Math.ceil(
    ((thursday.getTime() - jan4.getTime()) / 86400000 + jan4.getDay() + 1) / 7,
  )
  return `${year}-W${String(week).padStart(2, '0')}`
}

// ---------------------------------------------------------------------------
// Top tools horizontal bar chart
// ---------------------------------------------------------------------------

export function renderToolBar(toolCounts: Record<string, number>): string {
  const entries = Object.entries(toolCounts)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 10)

  if (entries.length === 0) {
    return `<svg viewBox="0 0 500 60" xmlns="http://www.w3.org/2000/svg">
  <text x="250" y="35" text-anchor="middle" font-size="13" fill="#8b949e">No tool data available</text>
</svg>`
  }

  const W = 500
  const rowH = 22
  const rowGap = 6
  const labelW = 130
  const barArea = W - labelW - 60
  const H = entries.length * (rowH + rowGap) + 10
  const maxCount = entries[0]?.[1] ?? 1

  const bars = entries
    .map(([name, count], i) => {
      const y = i * (rowH + rowGap) + 5
      const barW = Math.max(2, (count / maxCount) * barArea)
      const color = FALLBACK_COLORS[i % FALLBACK_COLORS.length] ?? '#58a6ff'
      return (
        `<text x="${labelW - 4}" y="${y + rowH - 5}" font-size="10" fill="#8b949e" text-anchor="end">${escHtml(name)}</text>` +
        `<rect x="${labelW}" y="${y + 2}" width="${barW.toFixed(1)}" height="${rowH - 4}" rx="2" fill="${color}" opacity="0.8">` +
        `<title>${escHtml(name)}: ${count}</title></rect>` +
        `<text x="${labelW + barW + 4}" y="${y + rowH - 5}" font-size="10" fill="#8b949e">${count}</text>`
      )
    })
    .join('')

  return `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" aria-label="Top tools">
  ${bars}
</svg>`
}

/**
 * Link graph construction: detects [[session_id]] / [[stem]] references
 * in clean markdown content and builds forward/backlink maps.
 */

import { existsSync, readFileSync } from 'node:fs'
import { basename, join } from 'node:path'

import type { ManifestEntry } from '../../types/transcript.js'
import type { LinkGraph } from '../../types/report.js'

// ---------------------------------------------------------------------------
// Link graph builder
// ---------------------------------------------------------------------------

export function buildLinkGraph(manifests: ManifestEntry[], root: string): LinkGraph {
  const forwardLinks: Record<string, string[]> = {}
  const backlinks: Record<string, string[]> = {}

  // Build lookup table: various identifiers → canonical session_id
  const lookup: Record<string, string> = {}
  for (const m of manifests) {
    // Register by session_id
    lookup[m.session_id] = m.session_id
    // Register by artifact stem (e.g. "019cf4b1-....__0ebaa458")
    const cleanPath = m.repo_clean_path || m.global_clean_path
    if (cleanPath) {
      const stem = basename(cleanPath, '.md')
      if (stem) lookup[stem] = m.session_id
    }
  }

  for (const m of manifests) {
    const cleanPath = resolveCleanPath(m, root)
    if (!cleanPath || !existsSync(cleanPath)) continue

    let content: string
    try {
      content = readFileSync(cleanPath, 'utf-8')
    } catch {
      continue
    }

    const refs = extractLinks(content)
    for (const ref of refs) {
      const targetId = lookup[ref]
      if (!targetId || targetId === m.session_id) continue // skip self-refs

      // Forward: m → target
      const fwd = forwardLinks[m.session_id]
      if (fwd) {
        if (!fwd.includes(targetId)) fwd.push(targetId)
      } else {
        forwardLinks[m.session_id] = [targetId]
      }

      // Backlink: target ← m
      const back = backlinks[targetId]
      if (back) {
        if (!back.includes(m.session_id)) back.push(m.session_id)
      } else {
        backlinks[targetId] = [m.session_id]
      }
    }
  }

  return { backlinks, forwardLinks }
}

// ---------------------------------------------------------------------------
// Link extraction
// ---------------------------------------------------------------------------

/** Extract all [[...]] references from text. */
export function extractLinks(content: string): string[] {
  const results: string[] = []
  const re = /\[\[([^\][\n]+)\]\]/g
  let match: RegExpExecArray | null
  while ((match = re.exec(content)) !== null) {
    const ref = match[1]?.trim()
    if (ref && ref.length > 0) {
      results.push(ref)
    }
  }
  return results
}

// ---------------------------------------------------------------------------
// Path helpers
// ---------------------------------------------------------------------------

export function resolveCleanPath(m: ManifestEntry, root: string): string | null {
  if (m.repo_clean_path) {
    return join(root, m.repo_clean_path)
  }
  if (m.global_clean_path) {
    return m.global_clean_path
  }
  return null
}

